+/// Fold select of symmetric selects with the same condition.
+/// Pattern: select c2, (select c1, a, b), (select c1, b, a)
+///   --> select (xor c1, c2), b, a
+///
+/// This is based on the identity:
+///   c2 ? (c1 ? a : b) : (c1 ? b : a)
+/// = (c2 && c1) ? a : (c2 && !c1) ? b : (!c2 && c1) ? b : a
+/// = (c1 == c2) ? a : b
+/// = (c1 xor c2) ? b : a
+static Instruction *foldSelectOfSymmetricSelects(SelectInst &SI,
+                                                 InstCombiner::BuilderTy &Builder) {
+  Value *CondVal = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+
+  // Both arms must be selects with the same condition.
+  auto *Sel1 = dyn_cast<SelectInst>(TrueVal);
+  auto *Sel2 = dyn_cast<SelectInst>(FalseVal);
+  if (!Sel1 || !Sel2)
+    return nullptr;
+
+  Value *Cond1 = Sel1->getCondition();
+  Value *Cond2 = Sel2->getCondition();
+
+  // Get the "effective" true/false values accounting for NOT conditions
+  Value *T1 = Sel1->getTrueValue();
+  Value *F1 = Sel1->getFalseValue();
+  Value *T2 = Sel2->getTrueValue();
+  Value *F2 = Sel2->getFalseValue();
+
+  // Check if conditions are the same or inverted.
+  if (Cond1 != Cond2) {
+    // Check if conditions are inverted (NOT).
+    Value *NotCond1;
+    Value *NotCond2;
+    bool Cond1IsNot = match(Cond1, m_Not(m_Value(NotCond1)));
+    bool Cond2IsNot = match(Cond2, m_Not(m_Value(NotCond2)));
+
+    if (Cond1IsNot && Cond2IsNot && NotCond1 == NotCond2) {
+      // Both conditions are NOT of the same value.
+      Cond1 = NotCond1;
+      Cond2 = NotCond2;
+      // sel1 = !c1 ? T1 : F1 = c1 ? F1 : T1
+      // sel2 = !c1 ? T2 : F2 = c1 ? F2 : T2
+      std::swap(T1, F1);
+      std::swap(T2, F2);
+    } else if (Cond1IsNot && NotCond1 == Cond2) {
+      // Cond1 = NOT(Cond2)
+      Cond1 = NotCond1;
+      // sel1 = !c2 ? T1 : F1 = c2 ? F1 : T1
+      std::swap(T1, F1);
+    } else if (Cond2IsNot && NotCond2 == Cond1) {
+      // Cond2 = NOT(Cond1)
+      Cond2 = NotCond2;
+      // sel2 = !c1 ? T2 : F2 = c1 ? F2 : T2
+      std::swap(T2, F2);
+    } else {
